fn collectAllText(node: *Node, buf: []u8, pos: usize) usize {
    var p = pos;
    if (node.text) |txt| {
        if (p > 0 and p < buf.len) { buf[p] = '\n'; p += 1; }
        const n = @min(txt.len, buf.len - p);
        if (n > 0) { @memcpy(buf[p..p+n], txt[0..n]); p += n; }
    }
    for (node.children) |*child| { p = collectAllText(child, buf, p); }
    return p;
}

