    _dyn_text_12 = std.fmt.bufPrint(&_dyn_buf_12, "{d} KB/s", .{ state.getSlot(5) }) catch "";
    _arr_11[1].text = _dyn_text_12;
    _dyn_text_13 = std.fmt.bufPrint(&_dyn_buf_13, "{d}/s", .{ state.getSlot(12) }) catch "";
    _arr_12[1].text = _dyn_text_13;
    _dyn_text_14 = std.fmt.bufPrint(&_dyn_buf_14, "{d}ms", .{ state.getSlot(13) }) catch "";
    _arr_13[1].text = _dyn_text_14;
    _dyn_text_15 = std.fmt.bufPrint(&_dyn_buf_15, "{d}%", .{ state.getSlot(14) }) catch "";
    _arr_15[1].text = _dyn_text_15;
    _dyn_text_16 = std.fmt.bufPrint(&_dyn_buf_16, "{d}", .{ state.getSlot(15) }) catch "";
    _arr_16[1].text = _dyn_text_16;
    _dyn_text_17 = std.fmt.bufPrint(&_dyn_buf_17, "{d}%", .{ state.getSlot(16) }) catch "";
